mapper.insert:
		/*
             SQL ID : ReshQstnDAO.insertReshPage
            	 설  명 : 설문 페이지 등록
         */
    	INSERT INTO TB_LMS_RESCH_PAGE (
    		  RESCH_PAGE_CD
			, SRVY_ID
			, RESCH_PAGE_TITLE
			, RESCH_PAGE_ARTL
			, RESCH_PAGE_ODR
			, RGTR_ID
			, FRST_INQ_DTTM
    	) VALUES (
    		  #{reschPageCd}
    		, #{reschCd}
    		, #{reschPageTitle}
    		, #{reschPageArtl}
    		, NVL((SELECT MAX(AA.RESCH_PAGE_ODR) + 1 FROM TB_LMS_RESCH_PAGE AA WHERE AA.SRVY_ID = #{reschCd}), 1)
    		, #{rgtrId}
    		, FN_DTTM()
    	)

mapper.update:
		/*
             SQL ID : ReshQstnDAO.updateReshPage
            	 설  명 : 설문 페이지 수정
         */
    	UPDATE TB_LMS_RESCH_PAGE SET
    		  MDFR_ID 		   = #{mdfrId}
    		, MOD_DTTM 		   = FN_DTTM()

    		, RESCH_PAGE_TITLE = #{reschPageTitle}


    		, RESCH_PAGE_ARTL  = #{reschPageArtl}

    	WHERE RESCH_PAGE_CD = #{reschPageCd}

mapper.delete:
		/*
             SQL ID : ReshQstnDAO.delReshPage
            	 설  명 : 설문 페이지 삭제
         */
    	DELETE FROM TB_LMS_RESCH_PAGE
    	 WHERE 1=1

    	   AND RESCH_PAGE_CD = #{reschPageCd}


    	   AND SRVY_ID = #{reschCd}

mapper.insert:
		/*
             SQL ID : ReshQstnDAO.insertReshQstn
            	 설  명 : 설문 항목 등록
         */
    	INSERT INTO TB_LMS_SRVY_QSTN (
    		  SRVY_QSTN_ID
			, RESCH_PAGE_CD
			, RESCH_QSTN_TYPE_CD
			, RESCH_QSTN_TITLE
			, RESCH_QSTN_CTS
			, RESCH_QSTN_ODR
			, REQ_CHOICE_YN
			, ETC_OPNNYN
			, MVMN_CHCYN
			, RESCH_SCALE_LVL
			, RGTR_ID
			, FRST_INQ_DTTM
    	) VALUES (
    		  #{reschQstnCd}
    		, #{reschPageCd}
    		, #{reschQstnTypeCd}
    		, #{reschQstnTitle}
    		, #{reschQstnCts}
    		, NVL((SELECT MAX(AA.RESCH_QSTN_ODR) + 1 FROM TB_LMS_SRVY_QSTN AA WHERE AA.RESCH_PAGE_CD = #{reschPageCd}), 1)
    		, #{reqChoiceYn}
    		, #{etcOpinionYn}
    		, #{jumpChoiceYn}
    		, #{reschScaleLvl}
    		, #{rgtrId}
    		, FN_DTTM()
    	)

mapper.update:
		/*
             SQL ID : ReshQstnDAO.updateReshQstn
            	 설  명 : 설문 항목 수정
         */
    	UPDATE TB_LMS_SRVY_QSTN SET
    		  MDFR_ID 			 = #{mdfrId}
    		, MOD_DTTM 			 = FN_DTTM()
    		, RESCH_QSTN_TYPE_CD = #{reschQstnTypeCd}
    		, RESCH_QSTN_TITLE 	 = #{reschQstnTitle}
    		, RESCH_QSTN_CTS 	 = #{reschQstnCts}
    		, REQ_CHOICE_YN 	 = #{reqChoiceYn}
    		, ETC_OPNNYN 	 = #{etcOpinionYn}
    		, MVMN_CHCYN 	 = #{jumpChoiceYn}
    		, RESCH_SCALE_LVL 	 = #{reschScaleLvl}
    	WHERE SRVY_QSTN_ID = #{reschQstnCd}

mapper.delete:
		/*
             SQL ID : ReshQstnDAO.delReshQstn
            	 설  명 : 설문 항목 삭제
         */
    	DELETE FROM TB_LMS_SRVY_QSTN
    	 WHERE 1=1

    	   AND SRVY_QSTN_ID = #{reschQstnCd}


    	   AND RESCH_PAGE_CD = #{reschPageCd}

mapper.insert:
		/*
             SQL ID : ReshQstnDAO.insertReshQstnItem
            	 설  명 : 설문 항목 아이템 등록
         */
    	INSERT INTO SRVY_VWITM (
    		  SRVY_VWITM_ID
			, SRVY_QSTN_ID
			, RESCH_QSTN_ITEM_TITLE
			, VWITM_SEQ
			, MVMN_PAGE
			, ETC_INPT_USEYN
			, RGTR_ID
			, FRST_INQ_DTTM
    	) VALUES (
    		  #{reschQstnItemCd}
    		, #{reschQstnCd}
    		, #{reschQstnItemTitle}
    		, #{itemOdr}
    		, #{jumpPage}
    		, #{etcItemYn}
    		, #{rgtrId}
    		, FN_DTTM()
    	)

mapper.update:
		/*
             SQL ID : ReshQstnDAO.updateReshQstnItem
            	 설  명 : 설문 항목 아이템 수정
         */
    	UPDATE SRVY_VWITM SET
    		  RESCH_QSTN_ITEM_TITLE = #{reschQstnItemTitle}
    		, VWITM_SEQ 				= #{itemOdr}
    		, MVMN_PAGE 			= #{jumpPage}
    		, ETC_INPT_USEYN 			= #{etcItemYn}
    		, MDFR_ID 				= #{mdfrId}
    		, MOD_DTTM 				= FN_DTTM()
    	WHERE SRVY_VWITM_ID = #{reschQstnItemCd}

mapper.delete:
		/*
             SQL ID : ReshQstnDAO.delReshQstnItem
            	 설  명 : 설문 항목 아이템 삭제
         */


    	DELETE FROM SRVY_VWITM A
	    WHERE EXISTS (
	        SELECT 1
	        FROM TB_LMS_SRVY_QSTN B
	        WHERE A.SRVY_QSTN_ID = B.SRVY_QSTN_ID

	            AND B.SRVY_QSTN_ID = #{reschQstnCd}


	            AND B.RESCH_PAGE_CD = #{reschPageCd}

	    )

    	   AND A.SRVY_VWITM_ID = #{reschQstnItemCd}

mapper.insert:
		/*
             SQL ID : ReshQstnDAO.insertReshScale
            	 설  명 : 설문 평가 척도 등록
         */
    	INSERT INTO TB_LMS_RESCH_SCALE (
    		  SRVY_SCALE_CD
			, SRVY_QSTN_ID
			, SCALE_ODR
			, EVL_TTL
			, EVL_SCR
			, RGTR_ID
			, FRST_INQ_DTTM
    	) VALUES (
    		  #{reschScaleCd}
    		, #{reschQstnCd}
    		, #{scaleOdr}
    		, #{scaleTitle}
    		, #{scaleScore}
    		, #{rgtrId}
    		, FN_DTTM()
    	)

mapper.update:
		/*
             SQL ID : ReshQstnDAO.updateReshScale
            	 설  명 : 설문 평가 척도 수정
         */
    	UPDATE TB_LMS_RESCH_SCALE SET
    		  SCALE_ODR 	= #{scaleOdr}
    		, EVL_TTL 	= #{scaleTitle}
    		, EVL_SCR 	= #{scaleScore}
    		, MDFR_ID 		= #{mdfrId}
    		, MOD_DTTM 		= FN_DTTM()
    	WHERE SRVY_SCALE_CD = #{reschScaleCd}

mapper.delete:
		/*
             SQL ID : ReshQstnDAO.delReshScale
            	 설  명 : 설문 평가 척도 삭제
         */

	    DELETE FROM TB_LMS_RESCH_SCALE A
	    WHERE EXISTS (
	        SELECT 1
	        FROM TB_LMS_SRVY_QSTN B
	        WHERE A.SRVY_QSTN_ID = B.SRVY_QSTN_ID

	            AND B.SRVY_QSTN_ID = #{reschQstnCd}


	            AND B.RESCH_PAGE_CD = #{reschPageCd}

	    )

	        AND A.SRVY_SCALE_CD = #{reschScaleCd}

mapper.update:
		/*
             SQL ID : ReshQstnDAO.updateReshPageOdr
            	 설  명 : 설문 페이지 순서 변경
         */
    	UPDATE TB_LMS_RESCH_PAGE SET

    		RESCH_PAGE_ODR = RESCH_PAGE_ODR + 1


    		RESCH_PAGE_ODR = RESCH_PAGE_ODR - 1

    	 WHERE SRVY_ID = #{reschCd}

    	   AND RESCH_PAGE_ODR BETWEEN #{newReschPageOdr} AND #{reschPageOdr}


    	   AND RESCH_PAGE_ODR BETWEEN #{reschPageOdr} AND #{newReschPageOdr}

		/*
             SQL ID : ReshQstnDAO.updateReshPageOdrToNo
            	 설  명 : 설문 페이지 순서 특정 번호로 변경
         */
    	UPDATE TB_LMS_RESCH_PAGE SET
    		RESCH_PAGE_ODR = #{newReschPageOdr}
    	 WHERE SRVY_ID = #{reschCd}
    	   AND RESCH_PAGE_CD = #{reschPageCd}

		/*
             SQL ID : ReshQstnDAO.updateReshQstnOdr
            	 설  명 : 설문 페이지별 항목 순서 변경
         */
    	UPDATE TB_LMS_SRVY_QSTN SET

    		RESCH_QSTN_ODR = RESCH_QSTN_ODR + 1


    		RESCH_QSTN_ODR = RESCH_QSTN_ODR - 1

    	 WHERE RESCH_PAGE_CD = #{reschPageCd}

    	   AND RESCH_QSTN_ODR BETWEEN #{newReschQstnOdr} AND #{reschQstnOdr}


    	   AND RESCH_QSTN_ODR BETWEEN #{reschQstnOdr} AND #{newReschQstnOdr}

		/*
             SQL ID : ReshQstnDAO.updateReshQstnOdrToNo
            	 설  명 : 설문 페이지별 항목 순서 특정 번호로 변경
         */
    	UPDATE TB_LMS_SRVY_QSTN SET
    		RESCH_QSTN_ODR = #{newReschQstnOdr}
    	 WHERE RESCH_PAGE_CD = #{reschPageCd}
    	   AND SRVY_QSTN_ID = #{reschQstnCd}
